// Fenêtre : événements qui commencent dans les prochains 7 jours
const now = new Date();
const max = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
return [{ json: {
  min_start: now.toISOString(),
  max_start: max.toISOString()
}}];

// Filtre les events déjà confirmés via static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.confirmed) staticData.confirmed = {};

// Nettoyer les entrées > 8 jours
const cutoff = Date.now() - 8 * 24 * 60 * 60 * 1000;
for (const [k, v] of Object.entries(staticData.confirmed)) {
  if (v < cutoff) delete staticData.confirmed[k];
}

const events = $json.collection || [];
const newEvents = events.filter(e => {
  const uuid = e.uri?.split('/').pop();
  return uuid && !staticData.confirmed[uuid];
});

return newEvents.map(e => ({
  json: {
    event_uuid: e.uri?.split('/').pop(),
    start_time: e.start_time,
    join_url: e.location?.join_url || e.location?.location || 'https://calendly.com/caroline-art-aibs/30min',
    event_name: e.name
  }
}));

// Aplatir invités + enrichir avec données event du nœud précédent
const eventItem = $('Filtrer nouveaux events').item.json;
const invitees = $json.collection || [];

return invitees
  .filter(inv => inv.status === 'active' && inv.email)
  .map(inv => ({
    json: {
      event_uuid: eventItem.event_uuid,
      start_time: eventItem.start_time,
      join_url: eventItem.join_url,
      invitee_email: inv.email,
      invitee_name: inv.name || '',
      invitee_uuid: inv.uri?.split('/').pop()
    }
  }));

// Construire message WA confirmation
const inviteeData = $('Aplatir invités').item.json;
const contacts = Array.isArray($json) ? $json : [];
const contact = contacts[0];

if (!contact?.id) return []; // contact non trouvé

const phones = Array.isArray(contact.phone_jsonb) ? contact.phone_jsonb : [];
const phone = phones[0]?.number || '';
if (!phone) return []; // pas de téléphone

// Formater date heure Paris (CEST = UTC+2)
const dt = new Date(inviteeData.start_time);
const parisHour = (dt.getUTCHours() + 2) % 24;
const timeStr = String(parisHour).padStart(2,'0') + 'h' + String(dt.getUTCMinutes()).padStart(2,'0');
const days = ['dimanche','lundi','mardi','mercredi','jeudi','vendredi','samedi'];
const months = ['','janvier','février','mars','avril','mai','juin','juillet','août','septembre','octobre','novembre','décembre'];
const dayStr = days[dt.getUTCDay()] + ' ' + dt.getUTCDate() + ' ' + months[dt.getUTCMonth()+1];

const firstName = (inviteeData.invitee_name || '').split(' ')[0] || 'vous';
const joinUrl = inviteeData.join_url || 'https://calendly.com/caroline-art-aibs/30min';

const message = `Bonjour ${firstName} ! 🎨\n\nVotre diagnostic de carrière artistique avec l'AIBS est confirmé pour le ${dayStr} à ${timeStr}.\n\nLien de connexion :\n${joinUrl}\n\nÀ très bientôt !`;

return [{
  json: {
    ...inviteeData,
    contact_id: contact.id,
    phone,
    message,
    date_str: dayStr + ' à ' + timeStr
  }
}];

// Email HTML de confirmation
const d = $('Préparer message').item.json;
const firstName = (d.invitee_name || '').split(' ')[0] || 'vous';
const joinUrl = d.join_url || 'https://calendly.com/caroline-art-aibs/30min';
const dateStr = d.date_str || 'date inconnue';
const toEmail = d.invitee_email || '';
if (!toEmail) return [];
return [{ json: {
  to: toEmail,
  subject: `Confirmation : votre diagnostic de carrière artistique avec l'AIBS — ${dateStr}`,
  html: `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family:Arial,sans-serif;max-width:600px;margin:auto;color:#333"><div style="background:#1a1a2e;padding:20px;text-align:center"><h2 style="color:#fff;margin:0">🎨 AIBS — Art International Business School</h2></div><div style="padding:30px"><p>Bonjour <strong>${firstName}</strong>,</p><p>Votre <strong>diagnostic de carrière artistique</strong> avec l'AIBS est confirmé :</p><div style="background:#f5f5f5;border-left:4px solid #27ae60;padding:15px;margin:20px 0"><strong>📅 ${dateStr}</strong></div><p>Rejoignez la réunion en cliquant ici :</p><p style="text-align:center"><a href="${joinUrl}" style="background:#27ae60;color:#fff;padding:12px 24px;text-decoration:none;border-radius:4px;display:inline-block">Rejoindre la réunion</a></p><p style="font-size:12px;color:#666">Ou copiez : ${joinUrl}</p><p>À très bientôt ! 🎨</p><p>L'équipe AIBS</p></div><div style="background:#f5f5f5;padding:15px;text-align:center;font-size:11px;color:#999">Art International Business School — contact@aibs.fr</div></body></html>`
}}];

// Marquer l'event comme confirmé dans le static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.confirmed) staticData.confirmed = {};
const uuid = $('Préparer message').item.json.event_uuid;
if (uuid) staticData.confirmed[uuid] = Date.now();
return $input.all();
